mapper.select:
SELECT lr.*,
       e1.name AS emp_name,
       e2.name AS approver_name,
       d.dept_name
FROM leave_request lr
INNER JOIN employee e1 ON lr.emp_id = e1.id
LEFT JOIN department d ON e1.dept_id = d.id
LEFT JOIN employee e2 ON lr.approver_id = e2.id
WHERE 1=1



    AND lr.emp_id = #{empId}



    AND lr.status = #{status}



    AND lr.approver_id = #{approverId}



    AND lr.leave_type = #{leaveType}



    AND lr.start_date >= #{startDate}


    AND lr.end_date <= #{endDate}


ORDER BY lr.id DESC
